toolArgs.file_text:
@using sv_a4bac5dc3f2f431f8964ec12d7ad69e1.Services

<div class="message-item @(isHovered ? "hovered" : "")"
     @onmouseenter="() => isHovered = true"
     @onmouseleave="() => { isHovered = false; showEmojiPicker = false; }">

    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp" title="@Message.SentAt.ToString("f")">@FormatRelativeTime(Message.SentAt)</span>
    </div>

    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (Thread is not null)
    {
        <button class="thread-link" @onclick="() => OnReplyClick.InvokeAsync(Message.Id)">
            💬 @Thread.ReplyCount @(Thread.ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (isHovered)
    {
        <div class="message-actions">
            <button class="action-btn" title="Reply in thread" @onclick="() => OnReplyClick.InvokeAsync(Message.Id)">
                💬 Reply
            </button>
            <div class="emoji-picker-wrapper">
                <button class="action-btn" title="Add reaction" @onclick="ToggleEmojiPicker">
                    😀 React
                </button>
                @if (showEmojiPicker)
                {
                    <div class="emoji-picker">
                        @foreach (var emoji in commonEmojis)
                        {
                            <button class="emoji-btn" @onclick="() => HandleReact(emoji)">@emoji</button>
                        }
                    </div>
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? Thread { get; set; }
    [Parameter] public EventCallback<int> OnReplyClick { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool isHovered;
    private bool showEmojiPicker;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "🔥"];

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task HandleReact(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

