arguments.file_text:
@using sv_a4bac5dc3f2f431f8964ec12d7ad69e1.Services

<nav class="channel-list">
    <h2 class="sidebar-title">Channels</h2>
    <div class="channel-items">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnClick="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</nav>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-list {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #2f3136;
    color: #dcddde;
    overflow: hidden;
}

.sidebar-title {
    padding: 1rem 0.75rem 0.5rem;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #72767d;
    font-weight: 700;
    margin: 0;
}

.channel-items {
    flex: 1;
    overflow-y: auto;
    padding: 0 0.5rem 0.5rem;
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
}

@using sv_a4bac5dc3f2f431f8964ec12d7ad69e1.Services

<aside class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" title="Close thread" @onclick="OnClose">✕</button>
    </div>

    <div class="thread-root">
        <div class="root-author">@RootMessage.Author</div>
        <div class="root-content">@RootMessage.Content</div>
    </div>

    <div class="thread-divider">
        <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
    </div>

    <div class="thread-messages">
        @foreach (var reply in Replies)
        {
            <MessageItem Message="reply"
                         OnReplyClick="OnReplyClick"
                         OnReact="OnReact" />
        }
    </div>

    <MessageInput ButtonText="Reply"
                  Placeholder="Reply in thread…"
                  OnSend="OnSendReply" />
</aside>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback<int> OnReplyClick { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #e0e0e0;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #2e3338;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    color: #72767d;
    cursor: pointer;
    padding: 0.25rem 0.4rem;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background: #f2f3f5;
    color: #2e3338;
}

.thread-root {
    padding: 0.75rem 1rem;
    background: #f9f9fa;
    border-bottom: 1px solid #e0e0e0;
}

.root-author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #2e3338;
    margin-bottom: 0.2rem;
}

.root-content {
    font-size: 0.9rem;
    color: #4f545c;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-divider {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.4rem 1rem;
    font-size: 0.75rem;
    color: #72767d;
    font-weight: 600;
}

.thread-divider::after {
    content: "";
    flex: 1;
    height: 1px;
    background: #e0e0e0;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 0.25rem 0;
}

@using sv_a4bac5dc3f2f431f8964ec12d7ad69e1.Services

<section class="message-area">
    <div class="area-header">
        @if (CurrentChannel is not null)
        {
            <h2># @CurrentChannel.Name</h2>
            <span class="area-desc">@CurrentChannel.Description</span>
        }
    </div>

    <div class="message-list" @onscroll="HandleScroll" @ref="messageListRef">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }

        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         Thread="@GetThread(message.Id)"
                         OnReplyClick="OnReplyClick"
                         OnReact="OnReact" />
        }

        @if (Messages.Count == 0 && CurrentChannel is not null)
        {
            <div class="empty-state">No messages yet. Start the conversation!</div>
        }
    </div>

    <MessageInput ButtonText="Send"
                  Placeholder="@($"Message #{CurrentChannel?.Name ?? "channel"}…")"
                  OnSend="OnSendMessage" />
</section>

@code {
    [Parameter] public Channel? CurrentChannel { get; set; }
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnReplyClick { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference messageListRef;

    private ThreadSummary? GetThread(int messageId) =>
        ThreadSummaries.GetValueOrDefault(messageId);

    private async Task HandleScroll()
    {
        // Scroll-to-top triggers loading older messages via JS interop would be
        // ideal, but we use a simple approach: invoke OnLoadMore when scrolled near top.
        await OnLoadMore.InvokeAsync();
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.area-header {
    display: flex;
    align-items: baseline;
    gap: 0.75rem;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.area-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #2e3338;
    white-space: nowrap;
}

.area-desc {
    font-size: 0.85rem;
