arguments.file_text:
@page "/chat"
@using sv_a4bac5dc3f2f431f8964ec12d7ad69e1.Services
@using sv_a4bac5dc3f2f431f8964ec12d7ad69e1.Components.Chat
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelList Channels="channels"
                     ActiveChannelId="selectedChannelId"
                     OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(threadRootMessage is not null ? "with-thread" : "")">
        <MessageArea CurrentChannel="selectedChannel"
                     Messages="messages"
                     ThreadSummaries="threadSummaries"
                     IsLoadingMore="isLoadingMore"
                     OnSendMessage="SendMessage"
                     OnReplyClick="OpenThread"
                     OnReact="HandleReact"
                     OnLoadMore="LoadOlderMessages" />
    </div>

    @if (threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply"
                         OnReplyClick="OpenThread"
                         OnReact="HandleReact" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private int selectedChannelId;
    private Channel? selectedChannel;

    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private bool isLoadingMore;
    private bool hasMoreMessages = true;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();

        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        hasMoreMessages = true;
        threadRootMessage = null;
        threadReplies = [];

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);

        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;

        var newMessage = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        messages.Add(newMessage);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);

        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            threadRootMessage.ChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary in main view
        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
            threadRootMessage.Id, threadReplies.Count, DateTime.Now);
    }

    private async Task HandleReact((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        messages = await ChatService.GetMessagesAsync(selectedChannelId, 0, messages.Count);

        if (threadRootMessage is not null)
        {
            threadReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);
        }
    }

    private async Task LoadOlderMessages()
    {
        if (isLoadingMore || !hasMoreMessages || selectedChannel is null) return;

        isLoadingMore = true;

        var older = await ChatService.GetMessagesAsync(selectedChannelId, messages.Count, PageSize);

        if (older.Count < PageSize)
        {
            hasMoreMessages = false;
        }

        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            BuildThreadSummaries();
        }

        isLoadingMore = false;
    }

    private void BuildThreadSummaries()
    {
        // Identify thread starters: messages that other messages reply to
        var replyGroups = messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in replyGroups)
        {
            var replies = group.ToList();
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key, replies.Count, replies.Max(r => r.SentAt));
        }
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
}

.chat-main.with-thread {
    /* When thread is open, main area takes ~55% */
    flex: 2.2;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

